using namespace std;
#define ll long long
const int N=5e5+5;
ll n,w,he[N];
struct A{
	ll s,q;
	double c;
	int id;
}a[N];
bool cmp(A B,A C){
	return B.c<C.c;
}
bool cmp2(A B,A C){
	return B.q<C.q;
}
ll b[N];

ll tr[N*4],cnt[N*4],L[N*4],R[N*4];
struct B{
	ll tr,cnt;
	friend B operator+=(B &C,B D){
		return C=B{C.tr+D.tr,C.cnt+D.cnt};
	} 
};
void build(int k,int l,int r){
	L[k]=l;R[k]=r;
	if(l==r){
		return;
	}
	int mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
}
void add(ll k,ll p){
	tr[k]+=b[p];
	cnt[k]++;
	if(L[k]==p&&R[k]==p){
		return;
	}
	int mid=(L[k]+R[k])/2;
	if(p<=mid)add(k*2,p);
	else add(k*2+1,p);
}
B cha(int k,double v){
	if(tr[k]<=v){
		return B{tr[k],cnt[k]};
	}
	if(L[k]==R[k]){
		return B{0,0};
	}
	B res={0,0};
	res+=cha(k*2,v);
	if(tr[k*2]<v)res+=cha(k*2+1,v-tr[k*2]);
	return res;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>w;
	for(int i=1;i<=n;i++){
		cin>>a[i].s>>a[i].q;
		a[i].c=1.0*a[i].s/a[i].q;
		a[i].id=i;
		b[i]=a[i].q;
	}
	sort(a+1,a+1+n,cmp);
	sort(b+1,b+1+n);
	for(int i=1;i<=n;i++){
		he[i]=he[i-1]+a[i].q;
		a[i].q=lower_bound(b+1,b+1+n,a[i].q)-b;
		//cout<<a[i].id<<"   "<<a[i].s<<' '<<a[i].q<<"   "<<a[i].c<<'\n';//
	}
	build(1,1,n);
	B ans={0,0};
	int p=0;
	for(int i=1;i<=n;i++){
		add(1,a[i].q);
		B o=cha(1,w/a[i].c);
		if(o.cnt>ans.cnt||(o.cnt==ans.cnt&&o.tr<ans.tr)){
			ans=o;
			p=i;
		}
	}
	sort(a+1,a+p+1,cmp2);
	cout<<ans.cnt<<'\n';
	for(int i=1;i<=ans.cnt;i++){
		cout<<a[i].id<<'\n';
	}
	return 0;
}
