#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,m,mod=1e9+7,b[200005];
struct A{ll l,r;};
vector<A>t[200005];
struct tree{
	int L,R;
	ll on,on_sum,off_sum,on_cnt,off_cnt,lazy_add,lazy_cheng;
	friend void operator*=(tree &b,ll c){
		if(b.on==0){
			b.lazy_cheng*=c;
			b.lazy_cheng%=mod;
			b.on_sum*=c;
			b.on_sum%=mod;
		}
	}
	friend void operator+=(tree &b,ll c){
		if(b.on==0){
			b.lazy_add+=c;
			b.lazy_add%=mod;
			b.on_sum+=c*b.on_cnt;
			b.on_sum%=mod;
		}

	}
}a[800005];
void build(ll k,ll l,ll r){
	a[k].lazy_cheng=1;
	a[k].L=l;a[k].R=r;
	if(l==r){
		a[k].on_cnt=1;
		a[k].on_sum=b[l];
		return;
	}
	ll mid=(l+r)/2;
	build(k*2,l,mid);
	build(k*2+1,mid+1,r);
	a[k].on_cnt=a[k*2].on_cnt+a[k*2+1].on_cnt;
	a[k].on_sum=a[k*2].on_sum+a[k*2+1].on_sum;
}
void update(ll k){
	a[k*2]*=a[k].lazy_cheng;
	a[k*2]+=a[k].lazy_add;
	a[k*2+1]*=a[k].lazy_cheng;
	a[k*2+1]+=a[k].lazy_add;
	a[k].lazy_cheng=1;
	a[k].lazy_add=0;
}
void cheng(ll k,ll l,ll r,ll v){
	if(a[k].on)return;
	if(a[k].L>=l&&a[k].R<=r){
		a[k]*=v;
		//cout<<"cheng "<<k<<' '<<a[k].L<<' '<<a[k].R<<"   "<<a[k].on<<' '<<a[k].on_sum<<' '<<a[k].off_sum<<'\n';// 
		return;
	}
	update(k);
	ll mid=(a[k].L+a[k].R)/2;
	if(l<=mid)cheng(k*2,l,r,v);
	if(r>=mid+1)cheng(k*2+1,l,r,v);
	a[k].on_sum=a[k*2].on_sum*!a[k*2].on+a[k*2+1].on_sum*!a[k*2+1].on;
	a[k].on_sum%=mod;
}
void add(ll k,ll l,ll r,ll v){
	if(a[k].on)return;
	if(a[k].L>=l&&a[k].R<=r){
		a[k]+=v;
		return;
	}
	update(k);
	ll mid=(a[k].L+a[k].R)/2;
	if(l<=mid)add(k*2,l,r,v);
	if(r>=mid+1)add(k*2+1,l,r,v);
	a[k].on_sum=a[k*2].on_sum*!a[k*2].on+a[k*2+1].on_sum*!a[k*2+1].on;
	a[k].on_sum%=mod;
}
struct B{ll sum,cnt;};
B on(ll k,ll l,ll r){
	if(a[k].L>=l&&a[k].R<=r){
		a[k].on--;
		if(a[k].on==0){
			//cout<<"ok";//
			return{a[k].on_sum,a[k].on_cnt};//需要on的和 需要on的数量 
		}
		return{0,0};
	}
	update(k);
	ll mid=(a[k].L+a[k].R)/2;
	B b={0,0},c={0,0};
	if(l<=mid)b=on(k*2,l,r);
	if(r>=mid+1)c=on(k*2+1,l,r);
	//cout<<"on a"<<k<<' '<<a[k].L<<' '<<a[k].R<<"   "<<a[k].on_sum<<' '<<a[k].off_sum<<'\n';//
	a[k].off_sum-=b.sum+c.sum;
	a[k].off_cnt-=b.cnt+c.cnt;
	a[k].on_sum+=b.sum+c.sum;
	a[k].on_cnt+=b.cnt+c.cnt;
	a[k].on_sum%=mod;a[k].off_sum=(a[k].off_sum+mod)%mod;
	//cout<<"on b"<<k<<' '<<a[k].L<<' '<<a[k].R<<"   "<<b.sum<<' '<<c.sum<<'\n';//
	return{(b.sum+c.sum)%mod,b.cnt+c.cnt};
}
B off(ll k,ll l,ll r){
	if(a[k].L>=l&&a[k].R<=r){
		a[k].on++;
		if(a[k].on==1){
			return{a[k].on_sum,a[k].on_cnt};//需要off的和 需要off的数量 
		}
		return{0,0};
	}
	update(k);
	ll mid=(a[k].L+a[k].R)/2;
	B b={0,0},c={0,0};
	if(l<=mid)b=off(k*2,l,r);
	if(r>=mid+1)c=off(k*2+1,l,r);
	a[k].off_sum+=b.sum+c.sum;
	a[k].off_cnt+=b.cnt+c.cnt;
	a[k].on_sum-=b.sum+c.sum;
	a[k].on_cnt-=b.cnt+c.cnt;
	a[k].off_sum%=mod;a[k].on_sum=(a[k].on_sum+mod)%mod;
	return{(b.sum+c.sum)%mod,b.cnt+c.cnt};
}
//bool jl=0;
ll cha(ll k,ll l,ll r){
	if(a[k].L>=l&&a[k].R<=r){
		//if(jl)cout<<"cha "<<k<<' '<<a[k].L<<' '<<a[k].R<<' '<<a[k].on_sum<<' '<<a[k].off_sum<<'\n';//
		return a[k].on_sum+a[k].off_sum;
	}
	update(k);
	ll mid=(a[k].L+a[k].R)/2,res=0;
	if(l<=mid)res+=cha(k*2,l,r);
	if(r>=mid+1)res+=cha(k*2+1,l,r);
	//if(jl)cout<<"cha "<<k<<' '<<a[k].L<<' '<<a[k].R<<' '<<res<<'\n';//
	return res%mod;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=n;i++)cin>>b[i];
	build(1,1,n);
	for(int i=1;i<=m;i++){
		ll o,l,r,x;
		cin>>o;
		if(o==1){
			cin>>l>>r>>x;
			add(1,l,r,x);
		}
		else if(o==2){
			cin>>l>>r>>x;
			cheng(1,l,r,x);
		}
		else if(o==3){
			cin>>l>>r>>x;
			t[x+i].push_back({l,r});
			off(1,l,r);
		}
		else{
			cin>>l>>r;
			cout<<cha(1,l,r)%mod<<'\n';
		}
		for(int l=0;l<t[i].size();l++){
			on(1,t[i][l].l,t[i][l].r);
		}
//		for(int l=1;l<=n;l++){
//			if(i==7&&l>=4&&l<=6)jl=1;
